        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == THEN || node.elementType == ELSE) {
            if (node.firstChildNode?.elementType == BLOCK) {
                return
            }

            if (node.elementType == ELSE && node.firstChildNode?.elementType == IF) {
                // The "else if" construct should not be wrapped with braces as "else { if (...) { } }".
                // The branches of the inner IF will be validated separately.
                return
            }

            if (!node.treePrev.textContains('\n')) {
